import json
import base64
import logging
from google.cloud import pubsub_v1

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

ALLOWED_JOB_TYPES = {"data_transform", "aggregation", "report_generation", "cleanup"}
REQUIRED_FIELDS = {"job_id", "job_type", "payload", "timestamp"}


def validate_job(job_data):
    """Validate the structure and content of a job."""
    if not isinstance(job_data, dict):
        raise ValueError("Job data must be a dictionary")

    missing_fields = REQUIRED_FIELDS - set(job_data.keys())
    if missing_fields:
        raise ValueError(f"Missing required fields: {missing_fields}")

    if job_data.get("job_type") not in ALLOWED_JOB_TYPES:
        raise ValueError(f"Invalid job type: {job_data.get('job_type')}. Allowed: {ALLOWED_JOB_TYPES}")

    if not isinstance(job_data.get("job_id"), str) or len(job_data["job_id"]) > 256:
        raise ValueError("job_id must be a string with max length 256")

    if not isinstance(job_data.get("payload"), dict):
        raise ValueError("payload must be a dictionary")

    return True


def process_data_transform(job_id, payload):
    """Handle data transformation jobs."""
    logger.info(f"Processing data transform job: {job_id}")
    source = payload.get("source", "")
    destination = payload.get("destination", "")
    if not isinstance(source, str) or not isinstance(destination, str):
        raise ValueError("source and destination must be strings")
    logger.info(f"Transforming data from {source} to {destination}")
    return {"status": "completed", "job_id": job_id}


def process_aggregation(job_id, payload):
    """Handle aggregation jobs."""
    logger.info(f"Processing aggregation job: {job_id}")
    metrics = payload.get("metrics", [])
    if not isinstance(metrics, list):
        raise ValueError("metrics must be a list")
    logger.info(f"Aggregating {len(metrics)} metrics")
    return {"status": "completed", "job_id": job_id}


def process_report_generation(job_id, payload):
    """Handle report generation jobs."""
    logger.info(f"Processing report generation job: {job_id}")
    report_type = payload.get("report_type", "")
    if not isinstance(report_type, str):
        raise ValueError("report_type must be a string")
    logger.info(f"Generating report of type: {report_type}")
    return {"status": "completed", "job_id": job_id}


def process_cleanup(job_id, payload):
    """Handle cleanup jobs."""
    logger.info(f"Processing cleanup job: {job_id}")
    target = payload.get("target", "")
    if not isinstance(target, str):
        raise ValueError("target must be a string")
    logger.info(f"Cleaning up target: {target}")
    return {"status": "completed", "job_id": job_id}


JOB_HANDLERS = {
    "data_transform": process_data_transform,
    "aggregation": process_aggregation,
    "report_generation": process_report_generation,
    "cleanup": process_cleanup,
}


def process_pubsub_message(event, context):
    """Cloud Function entry point for processing Pub/Sub messages.

    Uses JSON deserialization instead of pickle to prevent arbitrary code
    execution via deserialization attacks. Pickle is unsafe for untrusted
    input because a crafted pickle payload can execute arbitrary Python code
    during deserialization.

    Args:
        event: The Pub/Sub event payload.
        context: The event metadata/context.
    """
    try:
        if "data" not in event:
            logger.error("No data field in Pub/Sub message")
            return {"status": "error", "message": "No data in message"}

        raw_data = base64.b64decode(event["data"])

        try:
            job_data = json.loads(raw_data)
        except (json.JSONDecodeError, UnicodeDecodeError) as e:
            logger.error(f"Failed to deserialize message as JSON: {e}")
            return {"status": "error", "message": "Invalid JSON in message data"}

        validate_job(job_data)

        job_id = job_data["job_id"]
        job_type = job_data["job_type"]
        payload = job_data["payload"]
        timestamp = job_data["timestamp"]

        logger.info(f"Received job {job_id} of type {job_type} at {timestamp}")

        handler = JOB_HANDLERS.get(job_type)
        if handler is None:
            logger.error(f"No handler registered for job type: {job_type}")
            return {"status": "error", "message": f"No handler for job type: {job_type}"}

        result = handler(job_id, payload)

        logger.info(f"Job {job_id} completed with result: {result}")

        if event.get("attributes", {}).get("reply_topic"):
            publish_result(event["attributes"]["reply_topic"], result)

        return result

    except ValueError as e:
        logger.error(f"Validation error: {e}")
        return {"status": "error", "message": str(e)}
    except Exception as e:
        logger.error(f"Unexpected error processing message: {e}")
        return {"status": "error", "message": "Internal processing error"}


def publish_result(topic, result):
    """Publish processing result to a reply topic."""
    try:
        publisher = pubsub_v1.PublisherClient()
        message_data = json.dumps(result).encode("utf-8")
        future = publisher.publish(topic, data=message_data)
        logger.info(f"Published result to {topic}, message_id: {future.result()}")
    except Exception as e:
        logger.error(f"Failed to publish result: {e}")